// The AI Agent output is already in the correct format
const response = $input.item.json;

console.log('Received data:', JSON.stringify(response, null, 2));

// If the response is directly an array, use it
let songs = Array.isArray(response) ? response : response.output || response.text;

// If still not an array, try parsing as string
if (typeof songs === 'string') {
  songs = JSON.parse(songs);
}

// Final validation
if (!Array.isArray(songs)) {
  throw new Error(`Expected array but got: ${typeof songs}`);
}

// Récupérer le playlistId depuis Format Batch Data
const playlistId = $('Format Batch Data').first().json.playlistId;

console.log(`Processing ${songs.length} songs for batch playlist generation`);
console.log(`PlaylistId: ${playlistId}`);

// Return each song for parallel Spotify search with playlistId
return songs.map((song, index) => ({
  json: {
    artist: song.artist,
    song: song.song,
    searchQuery: `${song.song} ${song.artist}`,
    index: index,
    playlistId: playlistId
  }
}));

// Aggregate all Spotify track URIs
const allItems = $input.all();
const trackUris = [];
const foundSongs = [];

console.log('Processing', allItems.length, 'items from Spotify');

for (const item of allItems) {
  const track = item.json;

  // The Spotify node returns the track object directly
  if (track && track.uri && track.id && track.name) {
    trackUris.push(track.uri);
    foundSongs.push({
      name: track.name,
      artist: track.artists?.[0]?.name || 'Unknown',
      uri: track.uri,
      id: track.id
    });
  }
}

console.log('Total tracks found:', trackUris.length);

if (trackUris.length === 0) {
  throw new Error(`No valid tracks found`);
}

// Create comma-separated string of URIs for Spotify node
const trackUrisString = trackUris.join(',');

// ✅ RÉCUPÉRER LE PLAYLISTID DEPUIS PARSE JSON BODY (plus fiable)
const playlistId = $('Parse JSON Body').first().json.playlistId;

console.log('PlaylistId récupéré:', playlistId);

return [{
  json: {
    trackUris: trackUris,
    trackUrisString: trackUrisString,
    trackIds: trackUris.map(uri => uri.split(':')[2]),
    foundSongs: foundSongs,
    totalFound: trackUris.length,
    playlistId: playlistId
  }
}];

// Le webhook peut recevoir le body de différentes façons
const input = $json.body;

console.log('═══════════════════════════════════════');
console.log('Type du body:', typeof input);
console.log('Body reçu:', input);

let data;

// Cas 1 : Le body est déjà un objet
if (typeof input === 'object' && input !== null) {
  console.log('✅ Body déjà parsé comme objet');
  data = input;
}
// Cas 2 : Le body est une string JSON
else if (typeof input === 'string') {
  console.log('🔄 Body est une string, parsing nécessaire');
  console.log('Longueur:', input.length);
  console.log('Premiers 200 caractères:', input.substring(0, 200));

  try {
    // Essayer de parser directement
    data = JSON.parse(input);
    console.log('✅ Parsing JSON réussi');
  } catch (e) {
    console.log('❌ Erreur parsing direct:', e.message);
    console.log('Position de l\'erreur:', e.message.match(/position (\d+)/)?.[1]);

    // Afficher le contexte autour de l'erreur
    const pos = parseInt(e.message.match(/position (\d+)/)?.[1] || '0');
    const start = Math.max(0, pos - 50);
    const end = Math.min(input.length, pos + 50);
    console.log('Contexte erreur:', input.substring(start, end));

    throw new Error(`Impossible de parser le JSON: ${e.message}`);
  }
}
else {
  throw new Error(`Type de body inattendu: ${typeof input}`);
}

// Validation
if (!data.playlistId) {
  throw new Error('playlistId manquant dans les données');
}
if (!Array.isArray(data.players) || data.players.length === 0) {
  throw new Error('players manquant ou vide');
}

console.log('✅ Données validées:');
console.log('  PlaylistId:', data.playlistId);
console.log('  Nombre de joueurs:', data.players.length);
console.log('═══════════════════════════════════════');

// Retourner les données parsées
return [{
  json: {
    playlistId: data.playlistId,
    players: data.players
  }
}];
